Berikut implementasi CLI tool manajemen Docker menggunakan Python SDK (`docker-py`) dan `click`. Tool ini dirancang untuk efisiensi operasional server dengan error handling yang ketat.

### Prerequisites

Instal dependensi yang diperlukan:

```bash
pip install docker click
```

Pastikan user yang menjalankan script memiliki akses ke Docker socket (`/var/run/docker.sock`). Jangan jalankan sebagai root jika tidak diperlukan untuk prinsip least privilege.

### Source Code (`docker_cli.py`)

```python
#!/usr/bin/env python3
import sys
import click
import docker
from docker.errors import APIError, NotFound, DockerException

# Inisialisasi Docker Client
def get_client():
    try:
        return docker.from_env()
    except DockerException as e:
        click.echo(f"[CRITICAL] Gagal koneksi ke Docker Daemon: {e}", err=True)
        sys.exit(1)

@click.group()
def cli():
    """SherifNet Docker Management CLI"""
    pass

@cli.command()
def ls():
    """List semua container (aktif dan non-aktif)."""
    client = get_client()
    try:
        containers = client.containers.list(all=True)
        if not containers:
            click.echo("Tidak ada container ditemukan.")
            return

        click.echo(f"{'ID':<15} {'Nama':<25} {'Status':<20} {'Image':<30}")
        click.echo("-" * 90)
        for c in containers:
            status = c.status
            name = c.name[:24]
            image = c.image.tags[0] if c.image.tags else c.image.short_id
            click.echo(f"{c.short_id:<15} {name:<25} {status:<20} {image:<30}")
    except APIError as e:
        click.echo(f"[ERROR] API Error: {e.explanation}", err=True)

@cli.command()
@click.argument('container_id')
def start(container_id):
    """Start container berdasarkan ID atau Nama."""
    client = get_client()
    try:
        container = client.containers.get(container_id)
        container.start()
        click.echo(f"[OK] Container '{container.name}' berhasil dijalankan.")
    except NotFound:
        click.echo(f"[ERROR] Container '{container_id}' tidak ditemukan.", err=True)
    except APIError as e:
        click.echo(f"[ERROR] Gagal start container: {e.explanation}", err=True)

@cli.command()
@click.argument('container_id')
def stop(container_id):
    """Stop container dengan timeout default 10 detik."""
    client = get_client()
    try:
        container = client.containers.get(container_id)
        container.stop(timeout=10)
        click.echo(f"[OK] Container '{container.name}' berhasil dihentikan.")
    except NotFound:
        click.echo(f"[ERROR] Container '{container_id}' tidak ditemukan.", err=True)
    except APIError as e:
        click.echo(f"[ERROR] Gagal stop container: {e.explanation}", err=True)

@cli.command()
@click.argument('container_id')
@click.option('--force', is_flag=True, help="Force remove bahkan jika container berjalan.")
def rm(container_id, force):
    """Remove container. Gunakan --force untuk container berjalan."""
    client = get_client()
    try:
        container = client.containers.get(container_id)
        if force and container.status == 'running':
            container.remove(force=True)
            click.echo(f"[WARN] Container '{container.name}' di-force remove.")
        else:
            container.remove()
            click.echo(f"[OK] Container '{container.name}' berhasil dihapus.")
    except NotFound:
        click.echo(f"[ERROR] Container '{container_id}' tidak ditemukan.", err=True)
    except APIError as e:
        click.echo(f"[ERROR] Gagal remove container: {e.explanation}", err=True)

@cli.command()
@click.argument('container_id')
@click.option('--lines', default=100, help="Jumlah baris log terakhir.")
def logs(container_id, lines):
    """Tampilkan log container."""
    client = get_client()
    try:
        container = client.containers.get(container_id)
        log_output = container.logs(tail=lines).decode('utf-8')
        click.echo(log_output)
    except NotFound:
        click.echo(f"[ERROR] Container '{container_id}' tidak ditemukan.", err=True)
    except APIError as e:
        click.echo(f"[ERROR] Gagal mengambil log: {e.explanation}", err=True)

if __name__ == '__main__':
    cli()
```

### Cara Penggunaan

1.  **Berikan izin eksekusi:**
    ```bash
    chmod +x docker_cli.py
    ```

2.  **Jalankan perintah:**
    ```bash
    # List container
    ./docker_cli.py ls

    # Stop container spesifik
    ./docker_cli.py stop my_container

    # Remove container (aman)
    ./docker_cli.py rm my_container

    # Force remove container berjalan
    ./docker_cli.py rm --force my_container
    ```

### Catatan Keamanan (Security Advisory)

1.  **Akses Socket:** Akses ke `/var/run/docker.sock` setara dengan akses root. Pastikan permission file script ini terbatas (`chmod 700`) dan hanya user terpercaya yang bisa menjalankannya.
2.  **Input Validation:** Script menggunakan SDK Docker untuk handling ID/Nama, namun pastikan tidak ada input user yang tidak sanitized jika dikembangkan lebih lanjut untuk menerima input dinamis dari web.
3.  **Logging:** Untuk produksi, integrasikan logging ke syslog atau SIEM perusahaan (PT Sherif Network standard) untuk audit trail operasional container.

Gunakan tool ini untuk efisiensi manajemen server. Pastikan lingkungan production memiliki backup sebelum melakukan operasi `rm --force`.
